const out = $('#w1-out'), svg = $('#w1-svg');
function go(){
  const p = parseInt($('#w1-p').value,10);
  const a = parseInt($('#w1-a').value,10);
  const b = parseInt($('#w1-b').value,10);
  svg.innerHTML = '';
  if(!isPrime(p) || !Number.isFinite(a) || !Number.isFinite(b) || b===0){
    out.textContent = 'need a prime p and integers a,b with b\u22600';
    return;
  }
  const va = (a===0) ? '\u221E' : vpInt(a,p);
  const vb = vpInt(b,p);
  const v  = (a===0) ? '\u221E' : (vpInt(a,p) - vb);
  const absVal = (a===0) ? 0 : Math.pow(p, -v);
  out.textContent =
    `x = ${a}/${b}\n` +
    `v_${p}(${a}) = ${va}    v_${p}(${b}) = ${vb}    v_${p}(x) = ${v}\n` +
    `|x|_${p} = ${p}^(-${v}) = ${absVal.toPrecision(6)}\n` +
    `|x|_\u221E = ${Math.abs(a/b).toPrecision(6)}`;
  // bar chart: plot |x|_q for q in [2,3,5,7,11,13] (primes) plus infinity
  const primes = [2,3,5,7,11,13].filter(q=>q!==null);
  const W = 720, H = 160, pad = 30;
  const n = primes.length + 1;
  const bw = (W - 2*pad)/n * 0.6;
  const step = (W - 2*pad)/n;
  // each |x|_q
  const vals = primes.map(q=>{
    if(a===0) return 0;
    const vq = vpInt(a,q) - vpInt(b,q);
    return Math.pow(q, -vq);
  });
  const infVal = Math.abs(a/b);
  const all = [...vals, infVal];
  const maxV = Math.max(1e-6, ...all);
  primes.concat(['\u221E']).forEach((q, i) => {
    const x = pad + step*i + step*0.2;
    const val = (q==='\u221E') ? infVal : vals[i];
    const h = (H-pad-20) * (val / maxV);
    const color = (q===p) ? 'var(--yellow)' : (q==='\u221E' ? 'var(--pink)' : 'var(--blue)');
    svg.appendChild(SVG('rect',{x,y:H-pad-h,width:bw,height:h,fill:color,opacity:0.85}));
    const t1 = SVG('text',{x:x+bw/2,y:H-pad+14,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    t1.textContent = (q==='\u221E') ? '|x|\u221E' : `|x|_${q}`;
    svg.appendChild(t1);
    const t2 = SVG('text',{x:x+bw/2,y:H-pad-h-4,'text-anchor':'middle','font-size':10,fill:'var(--ink)'});
    t2.textContent = val.toPrecision(3);
    svg.appendChild(t2);
  });
}
