const out = $('#w2-out');
function go(){
  const p = parseInt($('#w2-p').value,10);
  const a = parseInt($('#w2-a').value,10);
  const b = parseInt($('#w2-b').value,10);
  const D = Math.max(1, Math.min(14, parseInt($('#w2-d').value,10)||10));
  if(!isPrime(p)){ out.textContent='p must be prime'; return; }
  if(b===0){ out.textContent='b cannot be zero'; return; }
  if(vpInt(b,p)>0){ out.textContent=`gcd(b,p) must be 1; your b has v_${p}(b)=${vpInt(b,p)}.\nfor such x the expansion begins at p^{-k}; try b coprime to p.`; return; }
  const digs = digitsOfRatInZp(a, b, p, D);
  if(!digs){ out.textContent='inversion failed'; return; }
  // check periodicity on the first half
  let period = null;
  for(let L=1; L<=Math.floor(D/2); L++){
    let ok = true;
    for(let i=0;i+L<D;i++){
      if(digs[i]!==digs[i+L]){ ok=false; break; }
    }
    if(ok){ period=L; break; }
  }
  const line = digs.map((d,i)=> (i===0?'':' + ') + (d===0 && i>0 ? '0' : d) + (i===0?'':'\u00b7'+p+(i===1?'':'^'+i))).join('');
  const vec = digs.join(' ');
  out.textContent =
    `x = ${a}/${b}  in base ${p}\n` +
    `digits a_0 a_1 a_2 ... : ${vec}  + O(${p}^${D})\n` +
    `x \u2248 ${line} + \u2026\n` +
    (period ? `eventually periodic, period \u2264 ${period}` : 'no short period detected in window');
}
$('#w2-go').addEventListener('click', go);
go();

