const svg = $('#w3-svg'), info = $('#w3-info');
let p = 3, maxDepth = 4;
// state: each node keyed by its digit tuple string, { expanded: bool }
let state = new Map();

function keyFor(digits){ return digits.join(','); }
function valueOf(digits){ // lift residue in Z/p^n given digits
  let s = 0, pw = 1;
  for(const d of digits){ s += d*pw; pw*=p; }
  return s;
}
function powP(n){ let r=1; for(let i=0;i<n;i++) r*=p; return r; }

function render(){
  svg.innerHTML = '';
  const W = 760, H = 420;
  // compute positions: at depth d, node gets an x-slot proportional to its cumulative digits
  // We'll walk and place visible nodes in rows.
  const rowY = d => 40 + d*(H-80)/Math.max(1,maxDepth);

  // root
  const rootX = W/2;
  const rootY = rowY(0);
  const nodes = []; // {x,y,digits,depth}
  const edges = []; // {x1,y1,x2,y2}

  function visit(digits, xMin, xMax){
    const depth = digits.length;
    const x = (xMin+xMax)/2;
    const y = rowY(depth);
    nodes.push({x,y,digits:digits.slice(),depth});
    const st = state.get(keyFor(digits));
    if(st && st.expanded && depth < maxDepth){
      const w = (xMax - xMin);
      for(let d=0; d<p; d++){
        const cxMin = xMin + w*d/p;
        const cxMax = xMin + w*(d+1)/p;
        const childDigits = digits.concat([d]);
        const cx = (cxMin+cxMax)/2;
        const cy = rowY(depth+1);
        edges.push({x1:x,y1:y,x2:cx,y2:cy, lbl:String(d)});
        visit(childDigits, cxMin, cxMax);
      }
    }
  }
  visit([], 40, W-40);

  // draw edges first
  edges.forEach(e=>{
    const ln = SVG('line',{x1:e.x1,y1:e.y1,x2:e.x2,y2:e.y2,stroke:'var(--line)','stroke-width':1.2});
    svg.appendChild(ln);
    const tx = (e.x1+e.x2)/2 + 6;
    const ty = (e.y1+e.y2)/2;
    const t = SVG('text',{x:tx,y:ty,'font-size':10,fill:'var(--mute)'});
    t.textContent = e.lbl;
    svg.appendChild(t);
  });
  // draw nodes
  nodes.forEach(n=>{
    const isRoot = n.depth===0;
    const st = state.get(keyFor(n.digits)) || {};
    const leafAtMax = n.depth === maxDepth;
    const expanded = !!st.expanded;
    const color = isRoot ? 'var(--yellow)' : (leafAtMax ? 'var(--violet)' : (expanded ? 'var(--cyan)' : 'var(--blue)'));
    const r = isRoot ? 22 : 14;
    const circ = SVG('circle',{cx:n.x,cy:n.y,r, fill:'var(--panel2)', stroke:color,'stroke-width':1.8, style:'cursor:pointer'});
    svg.appendChild(circ);
    const label = isRoot ? '\u2124_p' : String(valueOf(n.digits));
    const t = SVG('text',{x:n.x,y:n.y+4,'text-anchor':'middle','font-size':isRoot?13:11, fill:'#fff','font-weight':600, style:'cursor:pointer;pointer-events:none'});
    t.textContent = label;
    svg.appendChild(t);
    // interactions
    circ.addEventListener('click', ()=>{
      if(n.depth === maxDepth) return;
      const k = keyFor(n.digits);
      const s = state.get(k) || {expanded:false};
      s.expanded = !s.expanded;
      state.set(k, s);
      render();
    });
    circ.addEventListener('mouseenter', ()=>{
      if(isRoot){ info.textContent = '\u2124_p (whole ring)'; return; }
      const val = valueOf(n.digits);
      const mod = powP(n.depth);
      info.textContent = `${val} + ${p}^${n.depth}\u2124_p  (coset in \u2124/${p}^${n.depth} = ${val})`;
    });
  });
}

function reset(){
  state = new Map();
  state.set('', {expanded:true}); // root expanded by default
  render();
}
