const svg = $('#w6-svg'), out = $('#w6-out');
function term(n, series, p){
  if(series==='pn') return 1;      // multiplied by p^n below
  if(series==='factp'){ let f=1; for(let i=1;i<=n;i++) f*=i; return f; }
  if(series==='fact'){ let f=1; for(let i=1;i<=n;i++) f*=i; return f; }
  if(series==='invn') return n===0 ? 0 : 1/n;
  return 0;
}
function power(n, series, p){ // multiplier by power of p
  if(series==='pn') return Math.pow(p,n);
  if(series==='factp') return Math.pow(p,n);
  return 1;
}
function termValue(n, series, p){ return term(n,series,p) * power(n,series,p); }

// For |.|_p we track v_p of the *partial sum*, not just the term.
// Over Z, vp(sum) can be computed incrementally but we just use BigInt-like accumulation.
function run(){
  const series = $('#w6-series').value;
  const p = parseInt($('#w6-p').value,10);
  const N = Math.max(2, Math.min(24, parseInt($('#w6-N').value,10)||12));
