function go(){
  const p = parseInt($('#w5-p').value,10);
  const k = parseInt($('#w5-k').value,10);
  const x0 = parseInt($('#w5-x0').value,10);
  const N = Math.max(1, Math.min(12, parseInt($('#w5-n').value,10)||6));
  if(!isPrime(p)){ out.textContent='p must be prime'; return; }
  // Check hypotheses
  const f0 = ((x0*x0 - k) % p + p) % p;
  if(f0 !== 0){ out.textContent=`Hensel needs f(x_0) \u2261 0 (mod p).  Here ${x0}\u00b2-${k} \u2261 ${f0} (mod ${p}).`; return; }
  const df0 = ((2*x0) % p + p) % p;
  if(df0 === 0){ out.textContent=`Hensel needs f'(x_0) \u2262 0 (mod p).  Here 2\u00b7${x0} \u2261 0 (mod ${p}).`; return; }
  // Iterate Newton-in-Z/p^n form: lift modulo p^{n} increasing.
  // We compute x_n \in Z/p^{n+1} such that x_n^2 \equiv k (mod p^{n+1}).
  const lines = [`f(x)=x\u00b2-${k},  p=${p},  x_0=${x0}  (seed mod ${p})`];
  let pn = p; // modulus starts at p (we have x_0 mod p)
  let x  = ((x0 % pn) + pn) % pn;
  lines.push(`n=0   x_0 \u2261 ${x} (mod ${pn})   f(x_0) \u2261 ${(x*x - k) % pn} (mod ${pn})`);
  for(let n=1; n<=N; n++){
    const newPn = pn * p;
    // lift: find a in {0,..,p-1} with (x + a*pn)^2 \u2261 k (mod newPn)
    // (x^2 - k) + 2*x*a*pn \u2261 0 (mod p^{n+1})
    // a \u2261 -((x^2 - k)/pn) * (2x)^{-1}  (mod p)
    const delta = (x*x - k);
    // make sure delta is divisible by pn
    const deltaOverPn = Math.round(delta / pn);
    // inverse of 2x mod p
    const inv2x = modpow(((2*x)%p+p)%p, p-2, p);
    let a = ((-deltaOverPn * inv2x) % p + p) % p;
    const xNew = x + a*pn;
    const fv = (xNew*xNew - k);
    lines.push(`n=${n}   digit a_${n} = ${a}   x_${n} \u2261 ${xNew} (mod ${newPn})   f(x_${n}) \u2261 ${((fv % newPn)+newPn)%newPn} (mod ${newPn})`);
    x = xNew; pn = newPn;
  }
  lines.push(`\nLift converges: sqrt(${k}) \u2208 \u2124_${p} with digits a_0 a_1 ... giving x = ${x} (mod ${pn}).`);
  out.textContent = lines.join('\n');
}
