const out = $('#w7-out');
function go(){
  const a = parseInt($('#w7-a').value,10);
  const b = parseInt($('#w7-b').value,10);
  const c = parseInt($('#w7-c').value,10);
  const p = parseInt($('#w7-p').value,10);
  if(!isPrime(p)){ out.textContent='p must be prime'; return; }
  if(a===0 || b===0){ out.textContent='need a,b nonzero'; return; }
  const lines = [];
  // Real solvability: ax^2+by^2=c has real solutions iff c,a,b not forced to wrong signs.
  // Over R, ax^2 takes all values of sign(a)*[0,\u221E) and similarly for b, so ax^2+by^2 takes:
  //   if a>0,b>0: [0,\u221E); if a<0,b<0: (-\u221E,0]; otherwise all of R.
  let realOK;
  if(a>0 && b>0) realOK = (c>=0);
  else if(a<0 && b<0) realOK = (c<=0);
  else realOK = true;
  lines.push(`over \u211d: ax\u00b2+by\u00b2 with (a,b)=(${a},${b}) reaches ${realOK?'c='+c+' \u2713':'c='+c+' \u2717 (sign obstruction)'}`);
  // p-adic solvability heuristic: search modulo p^k for small k.
  // For good primes (p odd, not dividing abc, and not p=2 special), Hensel usually lifts any smooth point.
  // We do a brute search mod p^3.
  let pk = p*p*p; // p^3
  let found = null;
  outer:
  for(let x=0;x<pk;x++){
    for(let y=0;y<pk;y++){
      if(((a*x*x + b*y*y - c) % pk + pk) % pk === 0){
        // also require (x,y) not both \u2261 0 mod p, to rule out trivial scaling
        if(!(x%p===0 && y%p===0)){
          found = [x,y]; break outer;
        }
      }
      if(y>200) break; // safety
    }
    if(x>200) break;
  }
  if(found){
    lines.push(`over \u211a_${p}: primitive solution mod ${p}\u00b3 at (x,y)\u2261(${found[0]},${found[1]}), Hensel lifts \u2713`);
  } else {
    lines.push(`over \u211a_${p}: no primitive solution found mod ${p}\u00b3 in search window (likely obstruction)`);
  }
  const globalLikely = realOK && !!found;
  lines.push('');
  lines.push(globalLikely ?
    `local data consistent \u2014 by Hasse\u2013Minkowski a global \u211a-solution exists.` :
    `local obstruction detected \u2014 no global \u211a-solution (Hasse\u2013Minkowski).`);
  out.textContent = lines.join('\n');
}
